import { symbolsArr, randomSymbol } from './Symbols'

class Machine extends Component {
    constructor() {
        super();
        this.state = { 
            symbol1: randomSymbol(symbolsArr),
            symbol2: randomSymbol(symbolsArr),
            symbol3: randomSymbol(symbolsArr)
         }
         this.retry = this.retry.bind(this)
    }

retry() {
    this.setState({ 
        symbol1: randomSymbol(symbolsArr),
        symbol2: randomSymbol(symbolsArr),
        symbol3: randomSymbol(symbolsArr) 
    })
}

render() {
    const equal = this.state.symbol1 === this.state.symbol2 && this.state.symbol1 === this.state.symbol3;

    return (
        <div>
            <span>{this.state.symbol1}{this.state.symbol2}{this.state.symbol3}</span>
            <p>{equal ? 'WINNER!' : 'YOU LOST!'}</p>
            <button onClick={this.retry}>Try again!</button>
        </div>
    )
}
}

export default Machine

