class App extends Component {
  constructor(props) {
    super(props);

this.state = {
  customers: [],
  displayCustomers: true,
  displayCoins: false,
};
  }

  componentDidMount() {
    fetch('https://jsonplaceholder.typicode.com/users')
    .then(response => response.json())
    .then(users => this.setState({ customers: users }));
  }

  //logic to change display in container App
  changeToCustomers = () => {
    if(this.state.displayCoins) {
      this.setState({
        displayCustomers: true,
        displayCoins: false,
      });
    }
  }

  changeToCoins = () => {
    if(this.state.displayCustomers) {
      this.setState({
        displayCustomers: false,
        displayCoins: true,
      });
    }
  }

  render() {
    return(
      <div className='App'>
        <div className="tab-container">
          <button className="tab-button" onClick={this.changeToCustomers}> CUSTOMERS </button>
          <button className="tab-button" onClick={this.changeToCoins}> COINS </button>
        </div>
        {this.state.displayCustomers ? (
          <CardList customers={this.state.customers} />
        ) : (
          <Coins />
        )}
      </div>
    )
  }
}

function pipedString( str ){
    var value = str.toString();

return {
    removeDashes: function() {
        value = value.replace(/-/g, '');
        return this;
    },
    removeParens: function() {
        value = value.replace(/\(|\)/g, '');
        return this;
    },
    removeSpaces: function() {
        value = value.replace(/\s/g, '');
        return this;
    },
    toString: function (){
        return value;
    },
    valueOf: function (){
        return value;
    }
};
}

